SELECT NCPT.POINT_TXN_SEQ ,NCPT.POINT_TRT_CD ,NCPT.POINT ,NCPT.POINT_TXN_DTL_RSN_DESC ,TO_CHAR(NCPT.POINT_TRT_DT,'YYYY.MM.DD hh24:mi:ss') as POINT_TRT_DT FROM NMCP_CUST_POINT_GIVE_BASE_BAS NCPGBB ,NMCP_CUST_POINT_TXN NCPT WHERE NCPGBB.POINT_CUST_SEQ = NCPT.POINT_CUST_SEQ AND NCPGBB.SVC_CNTR_NO = #{cntrNo} AND TO_CHAR(NCPT.POINT_TRT_DT,'YYYY') = #{pointYyyy}
AND TO_CHAR(NCPT.POINT_TRT_DT,'MM') = #{pointMm}
AND POINT_TRT_CD = #{pointTrtCd}
ORDER BY POINT_TRT_DT DESC

SELECT
    count(*)
FROM
    NMCP_CUST_POINT_GIVE_BASE_BAS NCPGBB
    ,NMCP_CUST_POINT_TXN NCPT
WHERE
    NCPGBB.POINT_CUST_SEQ = NCPT.POINT_CUST_SEQ
    AND NCPGBB.SVC_CNTR_NO = #{cntrNo}
    AND TO_CHAR(NCPT.POINT_TRT_DT,'YYYY') = #{pointYyyy}

    AND TO_CHAR(NCPT.POINT_TRT_DT,'MM') = #{pointMm}


        AND POINT_TRT_CD = #{pointTrtCd}

