UPDATE NMCP_COUPN_OUTSIDE_BAS
   SET
    USER_ID = #{userId}
    ,SVC_CNTR_NO = #{svcCntrNo}
    ,SMS_RCV_NO = #{smsRcvNo}
    ,SMS_SND_YN = #{smsSndYn}


        ,SMS_SND_DT = SYSDATE


    ,SMS_SND_SUCCESS_YN = #{smsSndSuccessYn}
    ,COUPN_GIVE_DATE = #{coupnGiveDate}
    ,AMD_IP = #{cretIp}
    ,AMD_DT = SYSDATE
    ,AMD_ID	 = #{cretId}
WHERE COUPN_CTG_CD = #{coupnCtgCd}
  AND COUPN_NO = #{coupnNo}
  AND USE_YN = 'Y'
  AND TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN PSTNG_START_DATE AND PSTNG_END_DATE
  AND ROWNUM = 1

UPDATE NMCP_COUPN_MBERSHIP_BAS SET  /*MyBenefitMapper.updateCouponMbership*/
    USER_ID = #{userId}
    ,SVC_CNTR_NO = #{svcCntrNo}
    ,SMS_RCV_NO = #{smsRcvNo}
    ,SMS_SND_YN = #{smsSndYn}
    ,SMS_SND_DT = SYSDATE
    ,SMS_SND_SUCCESS_YN = #{smsSndSuccessYn}
    ,AMD_IP = #{amdIp}
    ,AMD_DT = SYSDATE
    ,AMD_ID	 = #{amdId}
    ,COUPN_GIVE_DATE = TO_CHAR(SYSDATE,'yyyymmddhh24miss')
WHERE 1 = 1
    AND COUPN_CTG_CD = #{coupnCtgCd}
    AND COUPN_NO = (SELECT MIN(COUPN_NO) FROM NMCP_COUPN_MBERSHIP_BAS
        WHERE 1 = 1
            AND COUPN_CTG_CD = #{coupnCtgCd}
            AND USE_YN = 'Y'
            AND COUPN_GIVE_DATE IS NULL)

UPDATE NMCP_COUPN_MBERSHIP_BAS SET  /*MyBenefitMapper.updateMbershipSmsFail*/
    SMS_SND_YN = 'N',
    SMS_SND_SUCCESS_YN = 'N'
WHERE 1 = 1
    AND COUPN_CTG_CD = #{coupnCtgCd}
    AND COUPN_NO = #{coupnNo}
    AND USER_ID = #{userId}

